# Three.js 着色器入门

## 什么是着色器？

着色器(Shader)是运行在GPU上的程序，用于控制图形渲染的各个阶段。Three.js主要使用两种着色器：

- **顶点着色器(Vertex Shader)**：处理每个顶点的位置
- **片元着色器(Fragment Shader)**：处理每个像素的颜色

## ShaderMaterial基础

```javascript
const material = new THREE.ShaderMaterial({
  vertexShader: `
    varying vec2 vUv;
    void main() {
      vUv = uv;
      gl_Position = projectionMatrix * modelViewMatrix * vec4(position, 1.0);
    }
  `,
  fragmentShader: `
    varying vec2 vUv;
    void main() {
      gl_FragColor = vec4(vUv, 0.0, 1.0);
    }
  `,
  uniforms: {}
})
```

## 常用Uniform变量

```javascript
const material = new THREE.ShaderMaterial({
  uniforms: {
    uTime: { value: 0 },
    uColor: { value: new THREE.Color(0xff0000) },
    uResolution: { value: new THREE.Vector2() }
  },
  vertexShader: vertexShader,
  fragmentShader: fragmentShader
})
```

## 创建波浪效果

### 顶点着色器

```glsl
varying vec2 vUv;
varying float vElevation;

uniform float uTime;

void main() {
  vUv = uv;

  vec4 modelPosition = modelMatrix * vec4(position, 1.0);
  float elevation = sin(modelPosition.x * 4.0 + uTime) * 0.1;
  elevation += sin(modelPosition.y * 4.0 + uTime) * 0.1;
  modelPosition.z += elevation;
  vElevation = elevation;

  vec4 viewPosition = viewMatrix * modelPosition;
  vec4 projectedPosition = projectionMatrix * viewPosition;
  gl_Position = projectedPosition;
}
```

### 片元着色器

```glsl
varying vec2 vUv;
varying float vElevation;

uniform vec3 uColor;

void main() {
  float mixStrength = (vElevation + 0.2) * 2.5;
  vec3 color = mix(uColor, vec3(1.0), mixStrength);
  gl_FragColor = vec4(color, 1.0);
}
```

## 使用噪声函数

```glsl
vec2 random2(vec2 p) {
  return fract(sin(vec2(
    dot(p, vec2(127.1, 311.7)),
    dot(p, vec2(269.5, 183.3))
  )) * 43758.5453);
}

float snoise(vec3 uv) {
  const vec2 C = vec2(1.0/6.0, 1.0/3.0);
  const vec4 D = vec4(0.0, 0.5, 1.0, 2.0);

  vec3 i = floor(uv + dot(uv, C.yyy));
  vec3 x0 = uv - i + dot(i, C.xxx);

  vec3 g = step(x0.yzx, x0.xyz);
  vec3 l = 1.0 - g;
  vec3 i1 = min(g.xyz, l.zxy);
  vec3 i2 = max(g.xyz, l.zxy);

  vec3 x1 = x0 - i1 + 1.0 * C.xxx;
  vec3 x2 = x0 - i2 + 2.0 * C.xxx;
  vec3 x3 = x0 - 1.0 + 3.0 * C.xxx;

  i = mod289(i);
  vec4 p = permute(permute(permute(
    i.z + vec4(0.0, i1.z, i2.z, 1.0))
    + i.y + vec4(0.0, i1.y, i2.y, 1.0))
    + i.x + vec4(0.0, i1.x, i2.x, 1.0));

  float n_ = 1.0/7.0;
  vec3 ns = n_ * D.wyz - D.xzx;

  vec4 j = p - 49.0 * floor(p * ns.z * ns.z);
  vec4 x_ = floor(j * ns.z);
  vec4 y_ = floor(j - 7.0 * x_);
  vec4 x = x_ * ns.x + ns.yyyy;
  vec4 y = y_ * ns.x + ns.yyyy;
  vec4 h = 1.0 - abs(x) - abs(y);

  vec4 b0 = vec4(x.xy, y.xy);
  vec4 b1 = vec4(x.zw, y.zw);

  vec4 s0 = floor(b0)*2.0 + 1.0;
  vec4 s1 = floor(b1)*2.0 + 1.0;
  vec4 sh = -step(h, vec4(0.0));

  vec4 a0 = b0.xzyw + s0.xzyw*sh.xxyy;
  vec4 a1 = b1.xzyw + s1.xzyw*sh.zzww;

  vec3 p0 = vec3(a0.xy, h.x);
  vec3 p1 = vec3(a0.zw, h.y);
  vec3 p2 = vec3(a1.xy, h.z);
  vec3 p3 = vec3(a1.zw, h.w);

  vec4 norm = taylorInvSqrt(vec4(dot(p0,p0), dot(p1,p1), dot(p2,p2), dot(p3,p3)));
  p0 *= norm.x;
  p1 *= norm.y;
  p2 *= norm.z;
  p3 *= norm.w;

  vec4 m = max(0.6 - vec4(dot(x0,x0), dot(x1,x1), dot(x2,x2), dot(x3,x3)), 0.0);
  m = m * m;
  return 42.0 * dot(m*m, vec4(dot(p0,x0), dot(p1,x1), dot(p2,x2), dot(p3,x3)));
}
```

## 完整示例

```javascript
import * as THREE from 'three'

const scene = new THREE.Scene()
const camera = new THREE.PerspectiveCamera(75, window.innerWidth / window.innerHeight, 0.1, 1000)
const renderer = new THREE.WebGLRenderer()

renderer.setSize(window.innerWidth, window.innerHeight)
document.body.appendChild(renderer.domElement)

const geometry = new THREE.PlaneGeometry(5, 5, 64, 64)
const material = new THREE.ShaderMaterial({
  uniforms: {
    uTime: { value: 0 },
    uColor: { value: new THREE.Color(0x6366f1) }
  },
  vertexShader: vertexShaderCode,
  fragmentShader: fragmentShaderCode,
  side: THREE.DoubleSide
})

const mesh = new THREE.Mesh(geometry, material)
mesh.rotation.x = -Math.PI / 2
scene.add(mesh)

camera.position.set(0, 3, 3)
camera.lookAt(0, 0, 0)

function animate(time) {
  requestAnimationFrame(animate)
  material.uniforms.uTime.value = time * 0.001
  renderer.render(scene, camera)
}

animate()
```

## 总结

着色器是Three.js中实现高级视觉效果的关键。通过自定义着色器，你可以：

1. 创建独特的视觉效果
2. 优化渲染性能
3. 实现复杂的动画
4. 控制渲染的每个细节

掌握着色器编程将使你的Three.js项目更上一层楼！

# Vue3 Composition API 完全指南

## 为什么使用Composition API？

Vue3引入的Composition API提供了一种新的方式来组织组件逻辑。相比于Options API，它具有以下优势：

- **更好的逻辑复用**：通过自定义Hook实现
- **更灵活的代码组织**：相关逻辑可以放在一起
- **更好的TypeScript支持**：类型推断更友好
- **更小的打包体积**：Tree-shaking更友好

## 响应式基础

### ref vs reactive

```javascript
import { ref, reactive } from 'vue'

// ref - 用于基本类型
const count = ref(0)
console.log(count.value) // 0
count.value++

// reactive - 用于对象
const state = reactive({
  name: 'Vue',
  version: 3
})
console.log(state.name) // 'Vue'
```

### computed

```javascript
import { ref, computed } from 'vue'

const count = ref(1)
const doubleCount = computed(() => count.value * 2)

console.log(doubleCount.value) // 2
count.value = 2
console.log(doubleCount.value) // 4
```

### watch

```javascript
import { ref, watch, watchEffect } from 'vue'

const count = ref(0)
const name = ref('Vue')

// 监听单个ref
watch(count, (newValue, oldValue) => {
  console.log(`count: ${oldValue} -> ${newValue}`)
})

// 监听多个源
watch([count, name], ([newCount, newName], [oldCount, oldName]) => {
  console.log('变化了')
})

// 立即执行
watch(count, callback, { immediate: true })

// watchEffect - 自动追踪依赖
watchEffect(() => {
  console.log(`count is: ${count.value}`)
})
```

## 生命周期钩子

```javascript
import { 
  onMounted, 
  onUpdated, 
  onUnmounted,
  onBeforeMount,
  onBeforeUpdate,
  onBeforeUnmount
} from 'vue'

onMounted(() => {
  console.log('组件已挂载')
})

onUpdated(() => {
  console.log('组件已更新')
})

onUnmounted(() => {
  console.log('组件已卸载')
})
```

## 自定义Hook

### 计数器Hook

```javascript
import { ref, computed } from 'vue'

export function useCounter(initialValue = 0) {
  const count = ref(initialValue)

  const doubleCount = computed(() => count.value * 2)

  function increment() {
    count.value++
  }

  function decrement() {
    count.value--
  }

  function reset() {
    count.value = initialValue
  }

  return {
    count,
    doubleCount,
    increment,
    decrement,
    reset
  }
}
```

### 使用Hook

```vue
<script setup>
import { useCounter } from './composables/useCounter'

const { count, doubleCount, increment, decrement, reset } = useCounter(10)
</script>

<template>
  <div>
    <p>Count: {{ count }}</p>
    <p>Double: {{ doubleCount }}</p>
    <button @click="increment">+</button>
    <button @click="decrement">-</button>
    <button @click="reset">重置</button>
  </div>
</template>
```

### 异步数据Hook

```javascript
import { ref, watchEffect } from 'vue'

export function useFetch(url) {
  const data = ref(null)
  const error = ref(null)
  const isLoading = ref(false)

  async function fetchData() {
    isLoading.value = true
    error.value = null

    try {
      const response = await fetch(url)
      if (!response.ok) throw new Error('请求失败')
      data.value = await response.json()
    } catch (err) {
      error.value = err.message
    } finally {
      isLoading.value = false
    }
  }

  watchEffect(() => {
    if (url.value) {
      fetchData()
    }
  })

  return { data, error, isLoading, refetch: fetchData }
}
```

## provide/inject

```javascript
import { provide, inject, ref } from 'vue'

// 父组件
const theme = ref('dark')
provide('theme', theme)

// 子组件
const theme = inject('theme')
```

## 总结

Composition API是Vue3的核心特性，它让我们能够：

1. **更好地组织代码**：相关逻辑放在一起
2. **更灵活地复用逻辑**：通过自定义Hook
3. **更好的TypeScript支持**：类型推断更完善
4. **更小的打包体积**：Tree-shaking友好

掌握Composition API是成为Vue3高手的必经之路！
